#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
bool canSum(vector<int>& nums, int target) {
    vector<bool> dp(target+1, false);
    dp[0] = true;
    for (int i = 0; i <= target; i++) {
        if (dp[i]) {
            for (int j = 0; j < nums.size(); j++) {
                if (i + nums[j] <= target) {
                    dp[i + nums[j]] = true;
                }
            }
        }
    }
    return dp[target];
}
};
int main() {
    int n, target;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    cin >> target;
    Solution solution;
    cout << boolalpha << solution.canSum(nums, target) << endl;
    return 0;
}
